import boto3
import json
import time

sqs = boto3.client('sqs')
queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/my-queue'

def process_type_a(message):
    print(f"Processing Type A: {message}")

def process_type_b(message):
    print(f"Processing Type B: {message}")

def process_type_c(message):
    print(f"Processing Type C: {message}")

def process_message(message):
    body = json.loads(message['Body'])
    msg_type = body.get('type')
    
    if msg_type == 'TYPE_A':
        process_type_a(body)
    elif msg_type == 'TYPE_B':
        process_type_b(body)
    elif msg_type == 'TYPE_C':
        process_type_c(body)
    else:
        print(f"Unknown message type: {msg_type}")

def poll_messages():
    while True:
        response = sqs.receive_message(
            QueueUrl=queue_url,
            MaxNumberOfMessages=10,
            WaitTimeSeconds=10
        )
        
        messages = response.get('Messages', [])
        
        for message in messages:
            process_message(message)
            sqs.delete_message(
                QueueUrl=queue_url,
                ReceiptHandle=message['ReceiptHandle']
            )

        time.sleep(1)

if __name__ == '__main__':
    poll_messages()